choose.when:
SELECT TOP 1

FROM BIO_FACEDATA
WHERE CASE WHEN ISNUMERIC(ID)=1 THEN CONVERT(BIGINT, ID) ELSE NULL END = #{enrollId,jdbcType=BIGINT}
  AND CONVERT(INT, FINDEX) = #{backupnum,jdbcType=INTEGER}
ORDER BY BP_ID DESC

