choose.when:
UPDATE BIO_USERMAST
SET PASSWD = LEFT(ISNULL(#{signatures,jdbcType=LONGVARCHAR}, ''), 10),
  UPD_DATE = GETDATE()
WHERE CASE WHEN ISNUMERIC(ID)=1 THEN CONVERT(BIGINT, ID) ELSE NULL END = #{enrollId,jdbcType=BIGINT}
  AND ISNULL(ISDELETED, 0) = 0;

UPDATE BIO_USERMAST
SET CARDNO = LEFT(ISNULL(#{signatures,jdbcType=LONGVARCHAR}, ''), 20),
  UPD_DATE = GETDATE()
WHERE CASE WHEN ISNUMERIC(ID)=1 THEN CONVERT(BIGINT, ID) ELSE NULL END = #{enrollId,jdbcType=BIGINT}
  AND ISNULL(ISDELETED, 0) = 0;

